// Extract recordId and stage from webhook body
const body = $input.first().json.body || $input.first().json;
const recordId = body.recordId || '';
const stage = body.stage ? parseInt(body.stage, 10) : null;

const STAGE_MAP = {
  1: { start: 7, ref: 8, stop: 7 },
  2: { start: 6, ref: 7, stop: 5 },
  3: { start: 4, ref: 5, stop: 3 },
  4: { start: 2, ref: 3, stop: 1 }
};

if (!recordId) {
  return [{ json: { error: true, stage: 'Image Generation', message: 'Missing recordId in request body.', recordId: '' } }];
}

if (stage !== null && !STAGE_MAP[stage]) {
  return [{ json: { error: true, stage: 'Image Generation', message: `Invalid stage "${stage}". Must be 1-4.`, recordId } }];
}

const stageInfo = stage ? STAGE_MAP[stage] : null;

return [{ json: { error: false, recordId, stage: stage, stageInfo } }];

// Validate project and Canon Drive URL
const project = $input.first().json;
const parsed = $('Code — Parse Input').first().json;
const recordId = parsed.recordId;
const stage = parsed.stage;
const stageInfo = parsed.stageInfo;

if (!project || !project.id) {
  return [{ json: { error: true, stage: 'Image Generation', message: `Failed to fetch project record ${recordId}. Check that the record exists in Airtable.`, recordId } }];
}

const projectName = project['Project Name'] || '';
const brandName = project['Brand Name'] || '';
const canonDriveUrl = project['Canon Drive URL'] || '';
const existingLog = project['Pipeline Log'] || '';

// For stage 1, the reference is the Canon Drive URL (Phase 8)
if (stage === 1 && !canonDriveUrl) {
  return [{ json: { error: true, stage: 'Image Generation', message: `Canon Drive URL is empty for project "${projectName}". Upload the canon image first.`, recordId, existingLog } }];
}

return [{ json: { error: false, recordId: project.id, projectName, brandName, canonDriveUrl, existingLog, stage, stageInfo } }];

// Validate both prompt records and build the Kie.AI job
const project = $('Code \u2014 Validate Project').first().json;
const stage = project.stage;
const stageInfo = project.stageInfo;
const startPhase = stageInfo.start;
const refPhase = stageInfo.ref;
const stopPhase = stageInfo.stop;

// Get start phase prompt from native Airtable search
const startItems = $('Airtable \u2014 Fetch Start Prompt').all();
if (startItems.length === 0) {
  return [{ json: { error: true, stage: 'Image Generation', message: `No image prompt record found for Phase ${startPhase} in project "${project.projectName}".`, recordId: project.recordId, existingLog: project.existingLog } }];
}
const startFields = startItems[0].json;
const startRecordId = startFields.id;
const genStatus = startFields['Generation Status'] || '';

if (genStatus !== 'pending' && genStatus !== 'failed') {
  return [{ json: { error: true, stage: 'Image Generation', message: `Phase ${startPhase} prompt has Generation Status "${genStatus}" (expected "pending" or "failed").`, recordId: project.recordId, existingLog: project.existingLog } }];
}

const editPromptText = startFields['Prompt Text'] || '';
if (!editPromptText) {
  return [{ json: { error: true, stage: 'Image Generation', message: `Phase ${startPhase} prompt has empty Prompt Text.`, recordId: project.recordId, existingLog: project.existingLog } }];
}

// Determine reference image URL
let referenceImageDriveUrl = '';
if (refPhase === 8) {
  // Canon image - use project's Canon Drive URL directly
  referenceImageDriveUrl = project.canonDriveUrl;
} else {
  // Use the reference phase's Drive URL
  const refItems = $('Airtable \u2014 Fetch Ref Prompt').all();
  if (refItems.length === 0) {
    return [{ json: { error: true, stage: 'Image Generation', message: `No image prompt record found for reference Phase ${refPhase} in project "${project.projectName}".`, recordId: project.recordId, existingLog: project.existingLog } }];
  }
  const refFields = refItems[0].json;
  const driveFileId = refFields['Drive File ID'] || '';
  if (!driveFileId) {
    return [{ json: { error: true, stage: 'Image Generation', message: `Reference Phase ${refPhase} has no Drive File ID. Generate that phase first.`, recordId: project.recordId, existingLog: project.existingLog } }];
  }
  referenceImageDriveUrl = `https://drive.google.com/uc?export=download&id=${driveFileId}`;
}

if (!referenceImageDriveUrl) {
  return [{ json: { error: true, stage: 'Image Generation', message: `Could not determine reference image URL for stage ${stage}.`, recordId: project.recordId, existingLog: project.existingLog } }];
}

// Build the Flux 2 Pro img2img callback URL
const callbackUrl = 'https://n8n.srv948776.hstgr.cloud/webhook/kie-callback'
  + '?type=tht_image'
  + '&table=tblWExmILcFYnW9ze'
  + '&record=' + encodeURIComponent(startRecordId)
  + '&project=' + encodeURIComponent(project.recordId)
  + '&phase=' + encodeURIComponent(startPhase)
  + '&chain=true'
  + '&next_phase=' + encodeURIComponent(startPhase - 1)
  + '&stop_phase=' + encodeURIComponent(stopPhase)
  + '&stage=' + encodeURIComponent(stage);

return [{
  json: {
    error: false,
    promptRecordId: startRecordId,
    referenceImageDriveUrl,
    editPromptText,
    callbackUrl,
    startPhase,
    refPhase,
    stopPhase,
    stage,
    projectId: project.recordId,
    projectName: project.projectName,
    existingLog: project.existingLog,
    recordId: project.recordId
  }
}];

// Return success response
const job = $('Code \u2014 Validate & Build Job').first().json;
return [{
  json: {
    status: 'submitted',
    message: `Stage ${job.stage} image job submitted for ${job.projectName}. Phase ${job.startPhase} generating with Phase ${job.refPhase} as reference. Callback chain will continue to Phase ${job.stopPhase}.`,
    projectId: job.projectId,
    stage: job.stage,
    startPhase: job.startPhase,
    refPhase: job.refPhase,
    stopPhase: job.stopPhase
  }
}];

// Error handler: write error to Pipeline Log and RESET status so user can retry
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
let errorData;

// Collect error info from whichever validation failed
try { errorData = $('Code \u2014 Parse Input').first().json; } catch(e) {}
if (!errorData?.error) try { errorData = $('Code \u2014 Validate Project').first().json; } catch(e) {}
if (!errorData?.error) try { errorData = $('Code \u2014 Validate & Build Job').first().json; } catch(e) {}
if (!errorData) errorData = { message: 'Unknown error in Image Generator', recordId: '', existingLog: '' };

const logEntry = `[${now}] \u2717 IMAGE ERROR: ${errorData.message}`;
const fullLog = errorData.existingLog ? errorData.existingLog + '\n' + logEntry : logEntry;

// Reset status to prompts_approved so user can just click Stage 1 again
return [{
  json: {
    recordId: errorData.recordId,
    logEntry,
    fullLog,
    status: 'prompts_approved',
    errorMessage: errorData.message
  }
}];

const err = $('Code \u2014 Build Error Log').first().json;
return [{
  json: {
    status: 'error',
    stage: 'Image Generation',
    error: err.errorMessage,
    recordId: err.recordId,
    pipelineLog: err.logEntry
  }
}];
